schedule.switchScript:
(function() {
  if (window.isProcessing) return;
  var yearSelect = document.getElementById('ddl_yms_year');
  var semSelect = document.getElementById('ddl_yms_smester');
  var btn = document.querySelector('button[name="PGcmd"][value="查詢"]');
  if (yearSelect && semSelect && btn) {
    var currentY = yearSelect.value;
    var currentS = semSelect.value;
    if (currentY !== '{{TARGET_YEAR}}' || currentS !== '{{TARGET_SEM}}') {
      window.isProcessing = true;
      yearSelect.value = '{{TARGET_YEAR}}';
      semSelect.value = '{{TARGET_SEM}}';
      btn.click();
    }
  }
})();

schedule.parseScript:
(function() {
  if (window.isProcessing) return;
  var table = document.querySelector('table.table-timetable');
  if (!table) return;
  window.isProcessing = true;
  var result = [];
  var slotMap = ['1','2','3','4','14','5','6','7','8','9','10','11','12','13'];
  for (var k = 0; k < slotMap.length; k++) {
    result.push({ slot: slotMap[k], days: [{},{},{},{},{},{},{}] });
  }
  var rows = table.querySelectorAll('tbody tr');
  var dataIndex = 0;
  for (var i = 0; i < rows.length; i++) {
    var tr = rows[i];
    var cols = tr.querySelectorAll('td.course-cell');
    if (cols.length >= 7 && dataIndex < result.length) {
      var currentSlot = result[dataIndex];
      for (var d = 0; d < 7; d++) {
        var cell = cols[d];
        var div = cell.querySelector('.course-text');
        var text = div ? div.innerText.trim() : cell.innerText.trim();
        if (text.length > 0) {
          var parts = text.split('/');
          var courseObj = {};
          if (parts.length >= 3) {
            courseObj = {
              id: parts[0].trim(),
              name: parts[1].trim().replace(/^[A-Z]/, ''),
              room: (parts[3] && parts[3].includes('教室')) ? parts[3].replace('教室','').trim() : (parts[3] || '').trim(),
              teacher: parts[4] ? parts[4].trim() : ''
            };
          } else {
            courseObj = { name: text, room: '', teacher: '' };
          }
          currentSlot.days[d] = courseObj;
        }
      }
      dataIndex++;
    }
  }
  if (window.mobileApp) {
    window.mobileApp.postMessage({ detail: { type: 'DATA_SUCCESS', payload: result }});
  }
})();

score.parseScript:
(function () {
    // 防重複送出鎖
    if (window._hasParsedScore) return;


    var url = location.href;


    // 1. 如果在首頁或跳轉頁，尋找成績頁按鈕並點擊跳轉
    if (url.indexOf("SB020") !== -1 || url.indexOf("baseuser/LoginSSO") !== -1) {
        var targetLink = document.querySelector('a[href*="SD100/Index"]');
        if (targetLink) targetLink.click();
        return; // 結束執行，等待網頁跳轉
    }


    // 2. 進入真實成績頁 (SD100) 的邏輯
    if (url.indexOf("SD100") !== -1) {
        // 處理 Bootstrap 5 阻擋彈窗
        var modal = document.getElementById("mySD100");
        if (
            modal &&
            (modal.classList.contains("show") || modal.style.display === "block")
        ) {
            var confirmBtn = modal.querySelector('button[value="確認SD100"]');
            if (confirmBtn) {
                confirmBtn.click();
                return;
            }
            var closeBtn = modal.querySelector('button[data-bs-dismiss="modal"]');
            if (closeBtn) {
                closeBtn.click();
                return;
            }
        }


        // 抓取成績表格
        var tables = document.querySelectorAll("#MyDiv table");
        if (tables.length === 0) return; // 還沒載入出來


        var results = [];


        tables.forEach(function (table) {
            var rows = table.querySelectorAll("tbody tr");
            rows.forEach(function (tr) {
                if (tr.innerText.indexOf("無資料") !== -1) return;


                var tds = tr.querySelectorAll("td");
                if (tds.length >= 7) {
                    var year = tds[0].innerText.trim();
                    var sem = tds[1].innerText.trim();
                    var className = tds[2].innerText.trim();
                    var type = tds[3].innerText.trim();
                    var subject = tds[4].innerText.trim();
                    var credit = tds[5].innerText.trim();
                    var scoreRaw = tds[6].innerText.trim();


                    var scoreNum = parseInt(scoreRaw);
                    var isPass = true;
                    var statusText = "及格";


                    if (
                        tds[6].querySelector(".text-danger") ||
                        (!isNaN(scoreNum) && scoreNum < 60)
                    ) {
                        isPass = false;
                        statusText = "不及格";
                    }


                    if (isNaN(scoreNum)) {
                        statusText = scoreRaw;
                        isPass = scoreRaw.indexOf("成績未到") !== -1 ? null : false;
                    }


                    var displayScore =
                        scoreRaw.indexOf("成績未到") !== -1 ? "-" : scoreRaw;


                    results.push({
                        term: year + "-" + sem,
                        subject: subject,
                        score: displayScore,
                        credit: credit,
                        type: type,
                        className: className,
                        isPass: isPass,
                        status: statusText,
                    });
                }
            });
        });


        // 統一使用 postMessage 發送結果
        if (results.length > 0) {
            window._hasParsedScore = true;
            if (window.mobileApp) {
                window.mobileApp.postMessage({
                    detail: { type: "DATA_SUCCESS", payload: results },
                });
            }
        }
    }
})();

news.apiRequestScript:
function formatDate(date) {
  var y = date.getFullYear();
  var m = String(date.getMonth() + 1).padStart(2, '0');
  var d = String(date.getDate()).padStart(2, '0');
  return y + '/' + m + '/' + d;
}
var today = new Date();
var threeDaysAgo = new Date();
threeDaysAgo.setDate(today.getDate() - 3);

return {
  TODAY: formatDate(today),
  P3D: formatDate(threeDaysAgo)
};

news.parseScript:
var parsedList = [];
if (responseData && responseData.data) {
  responseData.data.forEach(function(item) {
    if (Array.isArray(item) && item.length > 7) {
      var cleanTitle = (item[0] || '').replace(/<[^>]+>/g, "").trim().replace(/&amp;/g, "&");
      parsedList.push({
        title: cleanTitle,
        department: item[1],
        date: item[3].trim(),
        link: 'https://aps.ncue.edu.tw/odedi/doc_page.php?id=' + item[7]
      });
    }
  });
  parsedList.sort(function(a, b) { return b.date.localeCompare(a.date); });
}
return parsedList;

mail.webviewScript:
(function() {
  if (window._hasParsedMail) return;
  var rows = document.querySelectorAll('table tr');
  if (rows.length === 0) return;

  window._hasParsedMail = true;
  var result = [];

  for (var i = 0; i < rows.length; i++) {
    var cols = rows[i].querySelectorAll('td');
    if (cols.length >= 4) {
      var dept = cols[0].innerText.trim();
      var name = cols[1].innerText.trim();
      var date = cols[2].innerText.trim();
      var campus = cols[3].innerText.trim();

      if (name.length > 0 && name !== '姓名') {
        result.push({
          department: dept,
          name: name,
          date: date,
          campus: campus
        });
      }
    }
  }

  if (window.mobileApp) {
    window.mobileApp.postMessage({ detail: { type: 'MAIL_SUCCESS', payload: result }});
  }
})();
